import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Cloud',
        data: [30, 42, 38, 55, 48, 60],
      },
      {
        name: 'Hardware',
        data: [20, -8, 15, 12, -5, 18],
      },
      {
        name: 'Services',
        data: [15, 22, -10, 18, 25, 20],
      },
      {
        name: 'Licensing',
        data: [25, 18, 22, 14, 30, 24],
      },
    ],
    options: {
      chart: {
        type: 'bar',
        height: 350,
        stacked: true,
        toolbar: {
          show: true,
        },
      },
      stroke: {
        width: 1,
        colors: ['#fff'],
      },
      plotOptions: {
        bar: {
          horizontal: false,
          borderRadius: 10,
          borderRadiusApplication: 'end',
          borderRadiusWhenStacked: 'last',
          dataLabels: {
            total: {
              enabled: true,
              style: {
                fontSize: '13px',
                fontWeight: 900,
              },
            },
          },
        },
      },
      title: {
        text: 'Quarterly Profit & Loss by Segment',
        align: 'left',
      },
      xaxis: {
        categories: [
          'Q1 2024',
          'Q2 2024',
          'Q3 2024',
          'Q4 2024',
          'Q1 2025',
          'Q2 2025',
        ],
      },
      yaxis: {
        labels: {
          formatter: function (val) {
            return '$' + val + 'M'
          },
        },
      },
      legend: {
        position: 'right',
        offsetY: 40,
      },
      fill: {
        opacity: 1,
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="bar"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart
